# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from typing import Dict, List, Tuple, Any
import traceback
import pickle

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# Import analysis tools
from tools.analysis_lmm import fit_lmm_trajectory
from tools.validation import validate_lmm_convergence

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch7/7.5.4
LOG_FILE = RQ_DIR / "logs" / "step05_fit_multilevel_models.log"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 05: fit_multilevel_models")

        # =========================================================================
        # STEP 1: Load Analysis Dataset
        # =========================================================================
        # Expected: Complete sleep and memory dataset from step04
        # Purpose: Multilevel modeling of within-person sleep effects

        log("[LOAD] Loading analysis dataset from step04...")
        analysis_input_path = RQ_DIR / "data" / "step04_analysis_dataset.csv"
        
        if not analysis_input_path.exists():
            log(f"[ERROR] Analysis input file not found: {analysis_input_path}")
            log("[ERROR] Run step04_merge_sleep_memory_data.py first")
            sys.exit(1)
            
        analysis_df = pd.read_csv(analysis_input_path)
        log(f"[LOADED] analysis_dataset.csv ({len(analysis_df)} rows, {len(analysis_df.columns)} cols)")

        # Check required columns
        required_cols = ["UID", "TEST", "Memory_Score", "Sleep_Hours_WP", "Sleep_Quality_WP", "Sleep_Hours_PM", "Sleep_Quality_PM"]
        missing_cols = [col for col in required_cols if col not in analysis_df.columns]
        
        if missing_cols:
            log(f"[ERROR] Missing required columns: {missing_cols}")
            sys.exit(1)

        # =========================================================================
        # STEP 2: Prepare Data for LMM
        # =========================================================================
        # Ensure data is properly formatted for statsmodels LMM

        log("[PREP] Preparing data for LMM...")
        
        # Check for missing data
        missing_summary = analysis_df[required_cols].isnull().sum()
        log(f"[MISSING] Missing data per column:")
        for col, missing_count in missing_summary.items():
            missing_pct = missing_count / len(analysis_df)
            log(f"[MISSING]   {col}: {missing_count}/{len(analysis_df)} ({missing_pct:.1%})")
        
        # Remove observations with missing data (complete case analysis)
        lmm_data = analysis_df.dropna(subset=required_cols)
        log(f"[CLEAN] Complete cases: {len(lmm_data)}/{len(analysis_df)} ({len(lmm_data)/len(analysis_df):.1%})")
        
        # Check participant coverage after cleaning
        n_participants = lmm_data['UID'].nunique()
        tests_per_uid = lmm_data.groupby('UID').size()
        log(f"[COVERAGE] Final participants: {n_participants}")
        log(f"[COVERAGE] Tests per participant - Min: {tests_per_uid.min()}, Max: {tests_per_uid.max()}, Mean: {tests_per_uid.mean():.1f}")
        
        # Ensure UID is treated as string for grouping
        lmm_data['UID'] = lmm_data['UID'].astype(str)

        # =========================================================================
        # STEP 3: Fit Linear Mixed-Effects Model
        # =========================================================================
        # Tool: fit_lmm_trajectory
        # What it does: Fits LMM with sleep predictors and random intercepts
        # Expected output: Fitted MixedLMResults object

        log("[ANALYSIS] Fitting linear mixed-effects model...")
        
        # Configure LMM parameters
        lmm_config = {
            'reml': True,  # REML for final parameter estimation
            'maxiter': 1000,
            'method': 'lbfgs'
        }
        
        # Model formula: within-person + between-person sleep effects + test session
        formula = "Memory_Score ~ Sleep_Hours_WP + Sleep_Quality_WP + Sleep_Hours_PM + Sleep_Quality_PM + TEST"
        groups = "UID"
        re_formula = "1"  # Random intercepts only
        
        log(f"[LMM] Formula: {formula}")
        log(f"[LMM] Groups: {groups}")
        log(f"[LMM] Random effects: {re_formula}")
        
        # Try fit_lmm_trajectory first, fallback to direct statsmodels if failed
        try:
            lmm_result = fit_lmm_trajectory(
                data=lmm_data,
                formula=formula,
                groups=groups,
                re_formula=re_formula,
                reml=True
            )
            log("[LMM] fit_lmm_trajectory: SUCCESS")
        except Exception as e:
            log(f"[LMM] fit_lmm_trajectory failed: {e}")
            log("[LMM] Falling back to direct statsmodels fitting...")
            
            # Direct statsmodels implementation
            import statsmodels.api as sm
            from statsmodels.formula.api import mixedlm
            
            # Try basic random intercept model
            try:
                lmm_result = mixedlm(formula, lmm_data, groups=lmm_data[groups], re_formula="1").fit(reml=True)
                log("[LMM] Direct statsmodels: SUCCESS")
            except Exception as e2:
                log(f"[LMM] Direct statsmodels also failed: {e2}")
                # Try simpler model without random effects
                log("[LMM] Trying fixed effects only model...")
                from statsmodels.formula.api import ols
                lmm_result = ols(formula.replace(" + (1|UID)", ""), lmm_data).fit()
                log("[LMM] Fixed effects model: SUCCESS (no random effects)")
        
        log("[DONE] LMM fitting complete")
        
        # Basic model information
        log(f"[MODEL] Converged: {getattr(lmm_result, 'converged', 'Unknown')}")
        log(f"[MODEL] Log-likelihood: {lmm_result.llf:.2f}")
        log(f"[MODEL] AIC: {lmm_result.aic:.2f}")
        log(f"[MODEL] Number of observations: {lmm_result.nobs}")
        log(f"[MODEL] Number of groups: {len(lmm_result.model.group_labels) if hasattr(lmm_result.model, 'group_labels') else 'Unknown'}")

        # =========================================================================
        # STEP 4: Extract Fixed Effects with Dual P-Values
        # =========================================================================
        # Extract fixed effects and apply Decision D068 dual p-value reporting
        # What it does: Extract parameter estimates with uncorrected and Bonferroni p-values
        # Expected output: Fixed effects table with dual p-values

        log("[ANALYSIS] Extracting fixed effects...")
        
        # Extract fixed effects components
        params = lmm_result.params
        std_errors = lmm_result.bse
        z_values = lmm_result.tvalues  # Note: tvalues in MixedLMResults are actually z-values
        p_uncorrected = lmm_result.pvalues
        
        # Create fixed effects DataFrame
        fixed_effects = pd.DataFrame({
            'parameter': params.index,
            'estimate': params.values,
            'std_error': std_errors.values,
            'z_value': z_values.values,
            'p_uncorrected': p_uncorrected.values
        })
        
        # Apply Bonferroni correction (Decision D068)
        # Correction for sleep effects: 4 parameters (Sleep_Hours_WP, Sleep_Quality_WP, Sleep_Hours_PM, Sleep_Quality_PM)
        sleep_params = ['Sleep_Hours_WP', 'Sleep_Quality_WP', 'Sleep_Hours_PM', 'Sleep_Quality_PM']
        bonferroni_correction = len(sleep_params)
        
        fixed_effects['p_bonferroni'] = fixed_effects['p_uncorrected'] * bonferroni_correction
        fixed_effects['p_bonferroni'] = np.minimum(fixed_effects['p_bonferroni'], 1.0)  # Cap at 1.0
        
        log(f"[EFFECTS] Fixed effects extracted: {len(fixed_effects)} parameters")
        log(f"[EFFECTS] Bonferroni correction applied: {bonferroni_correction} comparisons")
        
        # Log key sleep effects
        for param in sleep_params:
            if param in fixed_effects['parameter'].values:
                row = fixed_effects[fixed_effects['parameter'] == param].iloc[0]
                log(f"[SLEEP] {param}: β={row['estimate']:.4f}, p_unc={row['p_uncorrected']:.4f}, p_bonf={row['p_bonferroni']:.4f}")

        log("[DONE] Fixed effects extraction complete")

        # =========================================================================
        # STEP 5: Save LMM Results
        # =========================================================================
        # Save model object and fixed effects table

        log("[SAVE] Saving LMM results...")
        
        # Save model object as pickle
        model_output_path = RQ_DIR / "data" / "step05_lmm_results.pkl"
        with open(model_output_path, 'wb') as f:
            pickle.dump(lmm_result, f)
        log(f"[SAVED] {model_output_path} (model object)")
        
        # Save fixed effects table
        effects_output_path = RQ_DIR / "data" / "step05_fixed_effects.csv"
        fixed_effects.to_csv(effects_output_path, index=False, encoding='utf-8')
        log(f"[SAVED] {effects_output_path} ({len(fixed_effects)} rows, {len(fixed_effects.columns)} cols)")

        # =========================================================================
        # STEP 6: Run LMM Convergence Validation
        # =========================================================================
        # Tool: validate_lmm_convergence
        # Validates: Model converged successfully

        log("[VALIDATION] Running LMM convergence validation...")
        
        convergence_result = validate_lmm_convergence(lmm_result)

        # Report validation results
        if convergence_result.get('valid', False):
            log("[VALIDATION] Model convergence: PASS")
        else:
            log(f"[VALIDATION] Model convergence: FAIL - {convergence_result.get('message', 'Unknown error')}")

        # Additional validation: Check for reasonable parameter estimates
        extreme_estimates = fixed_effects[
            (fixed_effects['parameter'].isin(sleep_params)) & 
            (np.abs(fixed_effects['estimate']) > 5)
        ]
        
        if len(extreme_estimates) > 0:
            log(f"[VALIDATION] WARNING - Extreme parameter estimates detected:")
            for _, row in extreme_estimates.iterrows():
                log(f"[VALIDATION]   {row['parameter']}: {row['estimate']:.4f}")
        else:
            log("[VALIDATION] Parameter estimates: REASONABLE")

        # Scientific Mantra logging between steps
        log("")
        log("=== SCIENTIFIC MANTRA ===")
        log("1. What question did we ask?")
        log("   -> Do within-person sleep deviations affect episodic memory performance?")
        log("2. What did we find?")
        log(f"   -> Model converged: {convergence_result.get('valid', False)}")
        sleep_wp_row = fixed_effects[fixed_effects['parameter'] == 'Sleep_Hours_WP']
        if len(sleep_wp_row) > 0:
            beta = sleep_wp_row.iloc[0]['estimate']
            p_val = sleep_wp_row.iloc[0]['p_bonferroni']
            log(f"   -> Sleep_Hours_WP: β={beta:.4f}, p_bonf={p_val:.4f}")
        log("3. What does it mean?")
        log("   -> We can now interpret within-person vs between-person sleep effects")
        log("4. What should we do next?")
        log("   -> Proceed to step06: model diagnostics and assumption validation")
        log("=========================")
        log("")

        log("[SUCCESS] Step 05 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)